import java.util.Scanner;

public class Main {
    public static int gcd(int a, int b) {
        if (b == 0) 
            return a;
        return gcd(b, a % b);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();

        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int g = gcd(N, M);
            int count = (N * M) / (g * g);
            System.out.println(count);
        }
    }
}

